<div>
    <div class="card mb-4">
        <div class="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
            <div>
                <h2 class="font-bold text-slate-900">Referensi Icon</h2>
                <p class="text-xs text-slate-500 mt-1">Kumpulan icon Heroicons (open source, MIT). Klik kartu icon untuk menyalin nama.</p>
            </div>
            <div class="flex items-center gap-2">
                <input wire:model.live.debounce.200ms="search" placeholder="Cari icon (book, user, …)" class="input w-64">
                <span class="text-xs text-slate-500 whitespace-nowrap">{{ count($filtered) }} icon</span>
            </div>
        </div>
    </div>

    <div
        x-data="{
            copy(name, target) {
                navigator.clipboard?.writeText(name);
                target.classList.add('ring-brand-500', 'ring-2');
                setTimeout(() => target.classList.remove('ring-brand-500', 'ring-2'), 700);
                window.dispatchEvent(new CustomEvent('toast', { detail: { type: 'success', message: 'Nama icon \"' + name + '\" disalin.' } }));
            }
        }"
        class="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-3"
    >
        @forelse ($filtered as $key => [$label, $svg])
            <button
                type="button"
                @click="copy('{{ $key }}', $event.currentTarget)"
                class="card hover:ring-brand-200 transition group cursor-pointer text-left flex flex-col items-center text-center p-4"
                title="Klik untuk salin nama"
            >
                <div class="flex h-12 w-12 items-center justify-center rounded-xl bg-brand-50 text-brand-600 group-hover:bg-brand-500 group-hover:text-white transition">
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" class="h-6 w-6">{!! $svg !!}</svg>
                </div>
                <div class="mt-3 font-semibold text-sm text-slate-900 leading-tight">{{ $label }}</div>
                <code class="mt-1 text-[11px] font-mono text-slate-500">{{ $key }}</code>
            </button>
        @empty
            <div class="col-span-full text-center text-slate-500 py-10 card">
                Tidak ada icon yang cocok dengan "{{ $search }}".
            </div>
        @endforelse
    </div>

    <div class="mt-6 card text-xs text-slate-600 leading-relaxed">
        <h3 class="font-semibold text-slate-900 mb-2">Cara Menggunakan</h3>
        <p>Pada form Program (kolom <strong>Icon</strong>), masukkan nama icon hasil copy (mis. <code class="font-mono bg-slate-100 px-1.5 py-0.5 rounded">book-open</code>) untuk merepresentasikan program tersebut. Icon ini juga dapat digunakan oleh developer untuk konsistensi di seluruh tampilan situs.</p>
    </div>
</div>
